var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"흐아아암......","JPN":"ふわあぁ……","ENG":"*Yawn*","TWN":"哈啊啊阿……"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"별일이네, 실비아. 이 시간에 네 얼굴을 다 보다니.","JPN":"珍しいこともあるものだ。こんな時間にシルビアに会うとはな。","ENG":"I must say I'm surprised, Sylvia. I never expected to see you at this hour.","TWN":"真是怪了，希爾維亞。這個時間竟然能遇到妳。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"간밤에 또 게임 하느라 밤을 새기라도 했니?","JPN":"また徹夜でゲームでもしていたのか？","ENG":"Have you been up all night playing video games again?","TWN":"昨晚又通宵打遊戲了嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"안뇽, 옆집 아줌마.","JPN":"ハロー、隣のおばさん。","ENG":"Hello.","TWN":"沒有啦，鄰家大嬸。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이번에 신규 레이드 보스가 나왔거든.","JPN":"今回、新しいレイドボスが出たのよ。","ENG":"They rolled out an update with a new raid boss.","TWN":"這次出了個新團隊副本BOSS。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"길드원들이랑 공략하다 보니까 벌써 이 시간이지 뭐야.","JPN":"ギルドメンバーたちと攻略してたら、こんな時間になっちゃったわ。","ENG":"I spent all night trying to take it down with my guild.","TWN":"為了和公會成員攻略這個副本，一不小心就玩到了這個時間。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하하, 그런 건 평소처럼 해킹을 해버리면 금방 클리어 할 수 있을 텐데?","JPN":"ハハ、そんなものハッキングしてしまえば、すぐにクリアできるのではないのか？","ENG":"Hah hah, can't you just hack your way through it like you always do?","TWN":"哈哈，像平時那樣黑掉程式不是很快就能通關了嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"무슨 바보 같은 소리야? 그럴 거면 게임을 왜 해?","JPN":"バカじゃないの？　そんなことするなら、何でゲームなんかするのよ。","ENG":"Don't be ridiculous! What would be the point of playing games then?","TWN":"妳在說什麼蠢話？那樣還玩什麼遊戲啊？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"내 역할은 오히려 매크로나 해킹 툴을 쓰면서 게임을 흐리는 녀석들을 응징하는 거라고.","JPN":"アタシはむしろ、マクロやハッキングツールを使ってゲームを汚すやつらを懲らしめてるの。","ENG":"If anything, my role is to bring justice to those halfwits who think it's clever to use macros and hacking tools.","TWN":"不如說我的任務是用巨集指令和駭客工具懲罰那些汙染遊戲環境的傢伙。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그나저나 아줌마야 말로 이 꼭두새벽에 뭐 해?","JPN":"それより、おばさんこそ朝っぱらから何してるの？","ENG":"Anyway, what are you doing up so early?","TWN":"不過大嬸妳才是，起這麼早是要幹什麼?"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"벌써 오전 5시야. 부지런한 사람들은 일터에 나가 있을 시간이지.","JPN":"もう午前5時だ。勤勉な者たちは仕事に向かっている時間だろう。","ENG":"It's already 5 a.m. Hard working people are already at their workplaces by now.","TWN":"已經早上5點了啊。這個時間，勤奮的人都已經在工作崗位上了。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐? 설마 이런 꼭두새벽에 출근한다고?","JPN":"えっ、こんな時間に出勤するってこと？","ENG":"What? You're going to work at this ungodly hour?","TWN":"什麼？這麼大清早就要上班？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"대단하네...... 나라면 아무리 돈을 많이 준다고 해도 이 시간에 출근은 무리야.","JPN":"すごーい……アタシだったらいくら大金積まれても、この時間に出勤はムリね。","ENG":"That's impressive... I don't think anyone could pay me enough to go to work this early.","TWN":"厲害了……我的話，就算給再多錢也沒辦法在這個時間出勤。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마도 나이가 있잖아? 얼마나 중요한 일을 하는지는 잘 모르지만 쉬엄쉬엄 하라고.","JPN":"おばさんもいい歳なんだし、どんだけ重要な仕事してるか知らないけど、休むことも大切よ。","ENG":"Think of your age. I don't know how important your job is, but take it easy.","TWN":"大嬸也一把年紀了吧？雖然不知道妳的工作有多重要，但也要懂得放鬆啊。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"적당한 게으름은 삶의 지혜야.","JPN":"適度な怠惰は人生の知恵なんだから。","ENG":"Laziness in moderation is a wise way to live life.","TWN":"適當的偷懶也是種生活的智慧。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"후후, 그렇게 요령 있는 성격이라면 나도 좋았을 텐데 말이지.","JPN":"ハハ、要領のいい性格だったら私も良かったのだがな。","ENG":"Hah hah, sometimes I wish I had such a flexible mindset.","TWN":"呵呵，我很喜歡妳這種懂得變通的性格。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그보다 아직 내가 무슨 일을 하는지 모르니?","JPN":"それより、私がどんな仕事をしているのか、まだわからないのか？","ENG":"By the way, you still don't know what I do for a living?","TWN":"不過，妳還不知道我從事什麼工作嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"천재 해커라고 해서 그 정도는 다 살펴봤을 줄 알았는데.","JPN":"天才ハッカーなのだから、それくらいはもう調査済みかと思ったが……","ENG":"I thought you'd have looked me up since you're a genius hacker and all.","TWN":"我還以為在天才駭客面前是藏不住秘密的呢。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐, 평소에 군복을 입고 있으니 군인이겠지 하는 정도?","JPN":"まぁ、普段から軍服着てるから軍人かなぁって感じ？","ENG":"Well, I figured you're in the military since you usually wear that uniform.","TWN":"我瞭解的頂多是“看她平時一直穿軍裝，大概是軍人”這樣？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 아무리 해커라고 해도 이웃집 사람의 개인정보 뒷조사 같은 건 절대 안 해.","JPN":"それにいくらハッカーだからって、隣人の個人情報を調べたりはしないわよ。","ENG":"Besides, just because I'm a hacker doesn't mean I go running background checks on my neighbors.","TWN":"而且就算是駭客，也絕對不會做什麼暗地裡調查鄰居個人資訊這種事。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이 직업에도 나름대로의 윤리와 원칙이라는 게 있거든?","JPN":"この職業にも一応モラルと原則があるの！","ENG":"Believe it or not, there are certain standards of conduct and ethics in my line of work, too.","TWN":"這一行也有自己的職業道德和原則。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하하, 그거 대단하군. 새로운 걸 하나 배웠는걸.","JPN":"ハハ、そうか。新しいことを一つ学んだな。","ENG":"Hah hah, that's impressive. I guess I learned something new today.","TWN":"哈哈，那可真是了不起。又學到新知識了。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그럼 난 출근할 테니까 이거나 받으렴.","JPN":"では私は出勤するとしよう。さぁ、受け取れ。","ENG":"Alright, then. I'm off to work. This is for you.","TWN":"那我先去上班了，妳收下這個吧。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이건......? 샌드위치잖아?","JPN":"これは……？　サンドイッチ？","ENG":"What's this? A sandwich?","TWN":"這是……？這不是三明治嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마가 직접 만든 거야?","JPN":"おばさんの手作りとか？","ENG":"Did you make it yourself?","TWN":"大嬸妳親手做的嗎？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아무리 나라고 해도 부대에서 주는 음식은 질리거든.","JPN":"いくら私でも、部隊に配給される食事だけでは飽きてしまうからな。","ENG":"Even with all those years of uniformed service under my belt, I get tired of the military cafeteria food sometimes.","TWN":"我也會有吃膩部隊餐的時候。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"가끔은 직접 만들어 먹는 것도 좋지.","JPN":"時々、手料理をするのもいいもんだ。","ENG":"So it's nice to make my own lunch from time to time.","TWN":"偶爾吃自己做的東西也很不錯啊。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"보나마나 밤새 게임 하느라 아무것도 안 먹었을 테니 꼭 챙겨먹고 자렴.","JPN":"朝までゲームに夢中で、何も食べていないのだろう？","ENG":"I bet you haven't eaten anything all night playing your video game. So be sure to grab a bite before you go to bed.","TWN":"妳一看就知道是一直在打遊戲什麼都沒吃，一定要好好吃完睡一覺才行。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아...... 타이밍 끝내 주게 좋네.","JPN":"うわぁ……超グッドタイミングね。","ENG":"Aww, that's perfect timing.","TWN":"哇……妳總是這麼及時呢。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"내가 이래서 아줌마를 좋아한다니까?","JPN":"これだから、おばさんのこと好きなのよ！","ENG":"This is why I like you, you know?","TWN":"所以我才特別喜歡大嬸妳喔？"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그럼 저녁에 또 보자. 안 자고 깨어 있다면 말이지.","JPN":"それじゃ、また夜に会おう。起きていたらの話だが。","ENG":"See you in the evening. If you're awake, that is.","TWN":"那晚上見吧。如果那時我還醒著的話。"},"stage":{"bg":"STREET_SPRING","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};